import { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import axios from "axios";
import Navbar from "../components/Navbar";

function EventDetails() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [event, setEvent] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const token = localStorage.getItem("token");

  useEffect(() => {
    const fetchEvent = async () => {
      try {
        const res = await axios.get(
          `http://localhost:5000/api/events/${id}`
        );
        setEvent(res.data);
      } catch (err) {
        console.error(err);
        setError("Failed to load event");
      } finally {
        setLoading(false);
      }
    };

    fetchEvent();
  }, [id]);

  const handleBooking = async () => {
    if (!token) {
      alert("Please login to book event");
      navigate("/login");
      return;
    }

    try {
      await axios.post(
        "http://localhost:5000/api/bookings",
        { eventId: id },
        {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        }
      );

      alert("Event booked successfully!");
      navigate("/mybookings");
    } catch (error) {
      alert("Booking failed. Please try again.");
    }
  };

  if (loading)
    return <h2 style={{ textAlign: "center", marginTop: "50px" }}>Loading...</h2>;

  if (error)
    return <h2 style={{ textAlign: "center", marginTop: "50px" }}>{error}</h2>;

  if (!event)
    return <h2 style={{ textAlign: "center", marginTop: "50px" }}>Event Not Found</h2>;

  return (
    <>
      <Navbar />

      <div style={styles.container}>
        <img
          src={event.image || "https://via.placeholder.com/800x400"}
          alt={event.title}
          style={styles.image}
        />

        <div style={styles.content}>
          <h1 style={styles.title}>{event.title}</h1>

          {event.category && (
            <p style={styles.category}>{event.category}</p>
          )}

          <p style={styles.description}>{event.description}</p>

          <div style={styles.details}>
            <p>
              <strong>Date:</strong>{" "}
              {event.date ? new Date(event.date).toDateString() : "N/A"}
            </p>
            <p>
              <strong>Location:</strong> {event.location || "N/A"}
            </p>
            <p>
              <strong>Price:</strong> ₹{event.price || 0}
            </p>
          </div>

          <button style={styles.button} onClick={handleBooking}>
            Book Now
          </button>
        </div>
      </div>
    </>
  );
}

const styles = {
  container: {
    maxWidth: "900px",
    margin: "40px auto",
    background: "#fff",
    borderRadius: "12px",
    overflow: "hidden",
    boxShadow: "0 6px 20px rgba(0,0,0,0.1)",
  },
  image: {
    width: "100%",
    height: "400px",
    objectFit: "cover",
  },
  content: {
    padding: "30px",
  },
  title: {
    fontSize: "32px",
    marginBottom: "10px",
  },
  category: {
    color: "#6C63FF",
    fontWeight: "bold",
    marginBottom: "15px",
  },
  description: {
    marginTop: "10px",
    lineHeight: "1.7",
    color: "#555",
  },
  details: {
    marginTop: "25px",
    fontSize: "18px",
  },
  button: {
    marginTop: "30px",
    padding: "14px 25px",
    backgroundColor: "#6C63FF",
    color: "#fff",
    border: "none",
    borderRadius: "8px",
    cursor: "pointer",
    fontSize: "16px",
    fontWeight: "bold",
  },
};

export default EventDetails;
